const rawContent = $input.item.json.message.content;

let parsed;
try {
  // コードブロックの除去
  const cleaned = rawContent
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { is_project: false, parse_error: e.message, raw: rawContent } }];
}

return [{ json: parsed }];
